from __future__ import annotations

from dataclasses import dataclass
from random import Random
from typing import Final
from collections import deque

WALL: Final[str] = "#"
FLOOR: Final[str] = "."
PLAYER: Final[str] = "@"

@dataclass(frozen=True)
class Point:
    x: int
    y: int

@dataclass
class Fighter:
    hp: int
    power: int

    @property
    def alive(self) -> bool:
        return self.hp > 0

@dataclass
class Entity:
    name: str
    pos: Point
    fighter: Fighter | None = None

@dataclass
class GameMap:
    width: int
    height: int
    tiles: list[list[str]]

    @classmethod
    def filled(cls, width: int, height: int, tile: str) -> GameMap:
        return cls(width, height, [[tile for _ in range(width)] for _ in range(height)])

    def in_bounds(self, point: Point) -> bool:
        return 0 <= point.x < self.width and 0 <= point.y < self.height

    def is_walkable(self, point: Point) -> bool:
        return self.in_bounds(point) and self.tiles[point.y][point.x] == FLOOR

    def count_floor_neighbors(self, point: Point) -> int:
        count = 0
        for dy in (-1, 0, 1):
            for dx in (-1, 0, 1):
                if dx == 0 and dy == 0:
                    continue
                neighbor = Point(point.x + dx, point.y + dy)
                if self.in_bounds(neighbor) and self.tiles[neighbor.y][neighbor.x] == FLOOR:
                    count += 1
        return count

def generate_cellular_automata(width: int, height: int, seed: int, fill_prob: float = 0.45) -> GameMap:
    rng = Random(seed)
    game_map = GameMap.filled(width, height, WALL)

    for y in range(height):
        for x in range(width):
            if rng.random() < fill_prob:
                game_map.tiles[y][x] = FLOOR

    for _ in range(4):
        new_tiles = [[WALL for _ in range(width)] for _ in range(height)]
        for y in range(height):
            for x in range(width):
                point = Point(x, y)
                floor_neighbors = game_map.count_floor_neighbors(point)
                if game_map.tiles[y][x] == FLOOR:
                    if floor_neighbors >= 4:
                        new_tiles[y][x] = FLOOR
                else:
                    if floor_neighbors >= 5:
                        new_tiles[y][x] = FLOOR
        game_map.tiles = new_tiles

    return game_map

def ensure_connectivity(game_map: GameMap, seed: int) -> None:
    floor_tiles = []
    for y in range(game_map.height):
        for x in range(game_map.width):
            if game_map.tiles[y][x] == FLOOR:
                floor_tiles.append(Point(x, y))

    if not floor_tiles:
        return

    visited: set[Point] = set()
    components: list[set[Point]] = []

    for tile in floor_tiles:
        if tile in visited:
            continue

        component: set[Point] = set()
        queue: deque[Point] = deque([tile])

        while queue:
            point = queue.popleft()
            if point in visited:
                continue
            visited.add(point)
            component.add(point)

            for dy in (-1, 0, 1):
                for dx in (-1, 0, 1):
                    if dx == 0 and dy == 0:
                        continue
                    neighbor = Point(point.x + dx, point.y + dy)
                    if (game_map.in_bounds(neighbor) and 
                        game_map.tiles[neighbor.y][neighbor.x] == FLOOR and 
                        neighbor not in visited):
                        queue.append(neighbor)

        components.append(component)

    while len(components) > 1:
        components.sort(key=len, reverse=True)
        main_component = components[0]
        other_component = components[1]

        min_distance = float('inf')
        closest_pair: tuple[Point, Point] | None = None

        for p1 in main_component:
            for p2 in other_component:
                distance = abs(p1.x - p2.x) + abs(p1.y - p2.y)
                if distance < min_distance:
                    min_distance = distance
                    closest_pair = (p1, p2)

        if closest_pair:
            p1, p2 = closest_pair
            if p1.x != p2.x:
                for x in range(min(p1.x, p2.x), max(p1.x, p2.x) + 1):
                    if game_map.in_bounds(Point(x, p1.y)):
                        game_map.tiles[p1.y][x] = FLOOR
            if p1.y != p2.y:
                for y in range(min(p1.y, p2.y), max(p1.y, p2.y) + 1):
                    if game_map.in_bounds(Point(p2.x, y)):
                        game_map.tiles[y][p2.x] = FLOOR

        main_component.update(other_component)
        components.pop(1)

@dataclass
class Game:
    game_map: GameMap
    player: Entity
    log: list[str]

    def move_player(self, dx: int, dy: int) -> None:
        destination = Point(self.player.pos.x + dx, self.player.pos.y + dy)
        if self.game_map.is_walkable(destination):
            self.player.pos = destination

def new_game(width: int = 40, height: int = 24, seed: int = 1) -> Game:
    game_map = generate_cellular_automata(width, height, seed)
    ensure_connectivity(game_map, seed)

    player_pos = Point(1, 1)
    for y in range(game_map.height):
        for x in range(game_map.width):
            if game_map.tiles[y][x] == FLOOR:
                player_pos = Point(x, y)
                break
        else:
            continue
        break

    player = Entity("player", player_pos, Fighter(hp=20, power=5))
    return Game(game_map, player, [])

def run_headless(seed: int, turns: int) -> Game:
    game = new_game(seed=seed)
    rng = Random(seed + 2000)
    moves = [Point(1, 0), Point(0, 1), Point(-1, 0), Point(0, -1)]
    for _ in range(turns):
        move = rng.choice(moves)
        game.move_player(move.x, move.y)
    return game

if __name__ == "__main__":
    run_headless(seed=123, turns=100)
